select * from bank_schema.bank_txns;
select * from bank_schema.stg_bank_txns;

TRUNCATE TABLE bank_schema.stg_bank_txns;

CREATE TABLE bank_schema.stg_bank_txns
WITH
(
    DISTRIBUTION = ROUND_ROBIN
)
AS
select * from bank_schema.bank_txns where 1=2;

--DROP PROCEDURE bank_schema.usp_ProcessBankData_WithLogic;
ALTER PROCEDURE bank_schema.usp_ProcessBankData_WithLogic
    @ProcessType NVARCHAR(20) -- Input parameter to choose logic
AS
BEGIN
    DECLARE @RowCount INT;

    -- 1. Check how many rows are in the staging table
    SELECT @RowCount = COUNT(*) FROM bank_schema.stg_bank_txns;

    -- 2. IF Condition: Check if staging is empty
    IF @RowCount = 0
    BEGIN
        PRINT 'No new data found in staging. Operation cancelled.';
    END
    ELSE
    BEGIN
        PRINT 'Found ' + CAST(@RowCount AS NVARCHAR(10)) + ' rows. Starting processing...';

        -- 3. Nested IF: Branching logic based on Input Parameter
        IF @ProcessType = 'INSERT'
        BEGIN
            -- Insert data from stg to main table
            INSERT INTO bank_schema.bank_txns select * from bank_schema.stg_bank_txns;
            TRUNCATE TABLE bank_schema.stg_bank_txns;
            PRINT 'Record Inserted Successfully. Record Count:' + CAST(@RowCount AS VARCHAR);
        END
        ELSE IF @ProcessType = 'RELOAD'
        BEGIN
            -- Wipe and reload logic
            DELETE FROM bank_schema.bank_txns;
            INSERT INTO bank_schema.bank_txns SELECT * FROM bank_schema.stg_bank_txns;
            PRINT 'Full reload completed.';
        END
        ELSE
        BEGIN
            PRINT 'Invalid ProcessType provided.';
        END
    END
END;


-- Execute/Call the stored procedure
EXEC bank_schema.usp_ProcessBankData_WithLogic @ProcessType = 'INSERT';

